import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import EmployeeLayout from '../components/EmployeeLayout';
import styles from '../pages/PageStyle2.module.css';

function AdminResetPasswordPage() {
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');
  const { id } = useParams();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (password !== confirmPassword) {
      setError('Passwords do not match');
      return;
    }
    setError('');
    setMessage('');

    try {
      const userInfo = JSON.parse(localStorage.getItem('userInfo'));
      const config = {
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${userInfo.token}`,
        },
      };
      await axios.put(`/api/users/${id}/reset-password`, { password }, config);
      setMessage('Password reset successfully!');
      setTimeout(() => navigate(-1), 2000); // Go back to previous page after 2 seconds
    } catch (err) {
      setError(err.response?.data?.message || 'An error occurred');
    }
  };

  return (
    <EmployeeLayout title="Reset User's Password">
      {error && <p className={styles.error}>{error}</p>}
      {message && <p style={{ color: 'green' }}>{message}</p>}
      <div>
        <form onSubmit={handleSubmit}>
          <div>
            <label>New Password:</label>
            <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required />
          </div>
          <div>
            <label>Confirm New Password:</label>
            <input
              type="password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              required
            />
          </div>
          <button type="submit">Save Password</button>
          <button type="button" onClick={() => navigate(-1)}>Cancel</button>
        </form>
      </div>
    </EmployeeLayout>
  );
}

export default AdminResetPasswordPage;
